-- Seed data for exercise_library
-- Content summary: exercise_library -> 50 rows
--   Barbell compounds (10), dumbbell staples (9), machine basics (6),
--   bodyweight/calisthenics (12), band work (3), cardio (10)

INSERT INTO exercise_library (name, muscle_group, equipment, instructions) VALUES
('Barbell back squat', 'legs', 'barbell', 'Set the bar on a squat rack at chest height and step under it so it rests across your upper traps, not your neck. Brace your core, keep your chest up, and push your knees out in line with your toes as you descend. Keep your weight balanced through your whole foot and avoid letting your knees cave inward as you drive back up.'),
('Bench press', 'chest', 'barbell', 'Lie on the bench with your eyes under the bar and feet flat on the floor. Grip the bar slightly wider than shoulder-width, unrack it over your chest, and lower it under control to touch your lower chest. Keep your shoulder blades pinned back and down throughout to protect your shoulders, and avoid bouncing the bar off your chest.'),
('Deadlift', 'back', 'barbell', 'Stand with the bar over your mid-foot, feet hip-width apart, and grip just outside your legs. Bend your knees until your shins touch the bar, keep your back flat and chest up, then drive through your heels to stand. Never round your lower back to force the weight up; if your form breaks, lower the weight instead.'),
('Overhead press', 'shoulders', 'barbell', 'Stand with feet shoulder-width apart and the bar resting on your front shoulders, hands just outside shoulder-width. Brace your core and glutes, then press the bar straight up, moving your head back slightly to let it pass, finishing with the bar over your ears. Avoid arching your lower back excessively to compensate; keep your ribs down throughout.'),
('Barbell row', 'back', 'barbell', 'Hinge at the hips with a flat back and slight knee bend, holding the bar with an overhand grip. Pull the bar to your lower ribs, squeezing your shoulder blades together, then lower with control. Keep your back flat and avoid jerking the weight up with momentum, the most common way people tweak their lower back on this lift.'),
('Romanian deadlift', 'legs', 'barbell', 'Hold the bar at hip height with a shoulder-width grip. Push your hips back while keeping a soft bend in your knees and the bar close to your legs, lowering until you feel a stretch in your hamstrings. Keep your back flat the whole way down and stop the descent before your back starts to round.'),
('Front squat', 'legs', 'barbell', 'Rest the bar across your front shoulders with elbows lifted high, using a crossed-arm or clean grip. Keep your torso upright as you squat down, letting your elbows lead the way back up. Keep your elbows up throughout; letting them drop is what causes the bar to roll forward and the torso to collapse.'),
('Incline bench press', 'chest', 'barbell', 'Set the bench to a 30-45 degree incline and lie back with feet flat on the floor. Grip the bar slightly wider than shoulders and lower it to your upper chest under control. Keep your shoulder blades retracted and avoid flaring your elbows out to 90 degrees, which stresses the shoulder joint.'),
('Sumo deadlift', 'legs', 'barbell', 'Stand with a wide stance, toes pointed out, and grip the bar inside your knees. Push your knees out over your toes and keep your chest tall as you drive the floor away. Keep your back flat and let your hips lead the lockout; don''t let your knees cave inward as you stand up.'),
('Barbell hip thrust', 'legs', 'barbell', 'Sit on the ground with your upper back against a bench and the bar rolled over your hips, feet flat. Drive through your heels to lift your hips until your body forms a straight line from shoulders to knees. Squeeze your glutes hard at the top and avoid overextending your lower back to gain extra height.'),

('Goblet squat', 'legs', 'dumbbells', 'Hold a dumbbell vertically against your chest with both hands cupping the top plate. Squat down between your knees, keeping your chest up and elbows brushing your inner knees. Keep your heels flat on the floor throughout to protect your knees and stay balanced.'),
('Dumbbell bench press', 'chest', 'dumbbells', 'Lie on a flat bench holding a dumbbell in each hand at chest level, palms facing your feet. Press the dumbbells up until your arms are extended, then lower them with control until you feel a stretch across your chest. Keep your shoulder blades pinned to the bench and don''t let the dumbbells drift too low, which can strain the shoulder.'),
('Dumbbell row', 'back', 'dumbbells', 'Place one knee and hand on a bench for support, holding a dumbbell in the opposite hand with your arm extended. Pull the dumbbell up to your hip, keeping your back flat and torso still. Avoid twisting your torso to heave the weight up; let your back muscles do the work.'),
('Dumbbell shoulder press', 'shoulders', 'dumbbells', 'Sit or stand with a dumbbell in each hand at shoulder height, palms facing forward. Press the dumbbells overhead until your arms are straight, then lower with control. Keep your core braced and avoid arching your lower back to press the weight up.'),
('Dumbbell lunge', 'legs', 'dumbbells', 'Stand tall holding a dumbbell in each hand at your sides. Step forward and lower your back knee toward the floor, keeping your front knee tracking over your ankle rather than caving inward. Push back through your front heel to return to standing.'),
('Dumbbell Romanian deadlift', 'legs', 'dumbbells', 'Hold a dumbbell in each hand in front of your thighs. Push your hips back with a soft knee bend, lowering the dumbbells along your legs until you feel a hamstring stretch. Keep your spine neutral throughout and avoid rounding your lower back at the bottom.'),
('Dumbbell bicep curl', 'arms', 'dumbbells', 'Stand holding a dumbbell in each hand with arms extended, elbows close to your sides. Curl the weights up by bending at the elbow only, then lower slowly. Keep your elbows pinned to your sides and avoid swinging your torso to sling the weight up.'),
('Dumbbell lateral raise', 'shoulders', 'dumbbells', 'Stand holding a light dumbbell in each hand at your sides. Raise your arms out to shoulder height with a slight bend in the elbows, leading with your elbows rather than your hands. Use a light weight and controlled tempo, since swinging heavy dumbbells here is the top cause of shoulder irritation.'),
('Dumbbell calf raise', 'legs', 'dumbbells', 'Stand holding a dumbbell in each hand, feet hip-width apart, optionally with your toes on a raised surface for extra range. Rise up onto your toes as high as possible, then lower slowly back down. Keep your knees straight but not locked and control the descent instead of dropping quickly.'),

('Leg press machine', 'legs', 'machine', 'Sit in the machine with your feet flat on the platform, shoulder-width apart. Lower the platform until your knees reach about 90 degrees, then press back up without locking your knees out hard. Keep your lower back flat against the pad and avoid letting your knees cave inward.'),
('Lat pulldown', 'back', 'machine', 'Sit at the machine with your thighs secured under the pads and grip the bar wider than shoulder-width. Pull the bar down to your upper chest while keeping your torso upright, then let it rise back with control. Avoid leaning back excessively or using momentum to yank the bar down.'),
('Seated cable row', 'back', 'machine', 'Sit with feet on the platform and knees slightly bent, gripping the handle with arms extended. Pull the handle to your torso while keeping your back straight, squeezing your shoulder blades together. Avoid rounding your lower back or using a big body swing to move the weight.'),
('Chest press machine', 'chest', 'machine', 'Adjust the seat so the handles line up with mid-chest height. Press the handles forward until your arms are extended, then return with control. Keep your shoulder blades pressed into the seat back and avoid shrugging your shoulders up toward your ears.'),
('Leg curl machine', 'legs', 'machine', 'Lie face down or sit, depending on the machine, with the pad positioned just above your heels. Curl your legs by bending your knees to bring your heels toward your glutes, then lower with control. Avoid jerking the weight with momentum and keep your hips pressed into the pad.'),
('Leg extension machine', 'legs', 'machine', 'Sit in the machine with the pad resting just above your ankles and your back against the seat. Extend your legs until they''re straight, then lower with control. Avoid locking your knees out forcefully at the top and use a weight that lets you move smoothly.'),

('Push-up', 'chest', 'none', 'Start in a plank position with hands slightly wider than shoulders and body in a straight line. Lower your chest toward the floor by bending your elbows at about a 45 degree angle from your body, then push back up. Keep your core braced so your hips don''t sag, which is what strains the lower back.'),
('Incline push-up', 'chest', 'none', 'Place your hands on a stable elevated surface like a bench or step, feet on the floor, body in a straight line. Lower your chest to the surface by bending your elbows, then press back up. Keep your hips in line with your shoulders and avoid letting them sag toward the floor.'),
('Pull-up', 'back', 'pull-up bar', 'Hang from a pull-up bar with hands slightly wider than shoulder-width, palms facing away. Pull yourself up until your chin clears the bar, then lower with control to a full arm extension. Avoid kipping or swinging your legs to generate momentum, which can strain your shoulders.'),
('Chin-up', 'back', 'pull-up bar', 'Hang from a pull-up bar with palms facing you, hands shoulder-width apart. Pull yourself up until your chin clears the bar, then lower under control to full extension. Keep your shoulders engaged at the bottom rather than letting them fully relax and roll forward.'),
('Dip', 'chest', 'none', 'Support yourself on parallel bars with arms straight, leaning slightly forward. Lower your body by bending your elbows until your shoulders are about level with your elbows, then press back up. Don''t descend deeper than that range, since going too low is the main cause of shoulder strain on dips.'),
('Plank', 'core', 'none', 'Start face down and prop yourself up on your forearms and toes, elbows under your shoulders. Keep your body in a straight line from head to heels by squeezing your glutes and bracing your core. Avoid letting your hips sag or pike up, which takes the load off your core.'),
('Side plank', 'core', 'none', 'Lie on your side propped up on one forearm, elbow under your shoulder, legs stacked. Lift your hips until your body forms a straight line from head to feet and hold. Keep your hips lifted and avoid letting them drop, which reduces the effectiveness and can strain your shoulder.'),
('Bodyweight squat', 'legs', 'none', 'Stand with feet shoulder-width apart, toes slightly turned out. Squat down by pushing your hips back and bending your knees, keeping your chest up and heels on the floor. Keep your knees tracking in line with your toes rather than caving inward as you stand back up.'),
('Glute bridge', 'legs', 'none', 'Lie on your back with knees bent and feet flat on the floor, hip-width apart. Drive through your heels to lift your hips until your body forms a straight line from shoulders to knees, squeezing your glutes at the top. Avoid overextending your lower back; the lift should come from your glutes, not arching your spine.'),
('Mountain climber', 'core', 'none', 'Start in a high plank position with hands under your shoulders. Drive one knee toward your chest, then quickly switch legs in a running motion while keeping your hips low and core braced. Keep your hips from bouncing up in the air, which reduces core tension and strains the lower back.'),
('Step-up', 'legs', 'none', 'Stand facing a sturdy bench or box, foot planted fully on top. Drive through that foot to step up until your leg is straight, then lower back down with control. Keep your knee tracking over your toes and avoid pushing off your trailing leg to help you up.'),
('Bird dog', 'core', 'none', 'Start on your hands and knees with a neutral spine. Extend one arm and the opposite leg out straight while keeping your hips and shoulders level, then return and switch sides. Move slowly and avoid letting your lower back arch or your hips rotate as you extend.'),

('Band pull-apart', 'shoulders', 'band', 'Hold a resistance band with both hands in front of you at shoulder height, arms extended. Pull the band apart by squeezing your shoulder blades together until your arms reach out to your sides. Keep your arms straight and avoid shrugging your shoulders up toward your ears.'),
('Band-assisted pull-up', 'back', 'band', 'Loop a resistance band around the pull-up bar and place one foot or knee in the loop. Perform a pull-up as usual, letting the band assist you at the bottom of the movement. Choose a band thickness that lets you complete full reps with good form, not just get your chin over the bar.'),
('Band face pull', 'shoulders', 'band', 'Anchor a band at chest height and hold an end in each hand, arms extended. Pull the band toward your face, leading with your elbows and rotating your hands back, squeezing your shoulder blades together. Keep your elbows high, at or above shoulder height, to properly target the rear shoulders and avoid neck strain.'),

('Brisk walk', 'cardio', 'none', 'Walk at a pace fast enough to raise your heart rate while still being able to hold a conversation. Keep your posture tall, swing your arms naturally, and land midfoot rather than overstriding on your heel. Wear supportive shoes and start with shorter distances if you''re new to regular walking.'),
('Easy run', 'cardio', 'none', 'Run at a conversational pace where you could speak in full sentences without gasping. Keep your strides short and quick rather than overstriding, landing under your body instead of way out in front. Start with a walk-run mix if you''re new to running to let your joints adapt gradually.'),
('Interval sprints', 'cardio', 'none', 'Warm up with 5-10 minutes of easy jogging first. Alternate short bursts of near-maximal effort running with longer recovery periods of walking or slow jogging. Always warm up thoroughly before sprinting, since sprinting cold is the most common cause of hamstring strains.'),
('Stationary bike', 'cardio', 'cardio equipment', 'Adjust the seat height so your knee has a slight bend at the bottom of the pedal stroke. Pedal at a steady, comfortable resistance, keeping your back straight and core engaged. A seat that''s too low is the main cause of knee pain on the bike, so double-check the height before you start.'),
('Rowing machine', 'cardio', 'cardio equipment', 'Strap your feet in securely and grip the handle with arms extended. Drive with your legs first, then lean back slightly and pull the handle to your ribs, reversing the order on the way back. Keep the sequence legs-back-arms on the drive and arms-back-legs on the return to protect your lower back.'),
('Jump rope', 'cardio', 'none', 'Hold the rope handles at hip height and turn it primarily with your wrists, not your whole arms. Jump just high enough to clear the rope, landing softly on the balls of your feet. Keep your knees slightly bent throughout to absorb impact and protect your ankles and shins.'),
('Cycling', 'cardio', 'cardio equipment', 'Set your seat height so your knee has a slight bend at the bottom of the pedal stroke. Keep a steady cadence and shift gears to avoid grinding against heavy resistance. Keep your elbows slightly bent to absorb road vibration and protect your wrists.'),
('Treadmill incline walk', 'cardio', 'cardio equipment', 'Set the treadmill to a moderate incline and a brisk walking pace. Hold the side rails only briefly if needed for balance, not to support your weight, and keep your posture upright. Avoid leaning heavily on the front console, which reduces the workout and strains your lower back.'),
('Elliptical', 'cardio', 'cardio equipment', 'Step onto the pedals and grip the moving handles, keeping your posture tall and core engaged. Push and pull smoothly through the full range of motion rather than taking short, choppy strides. Keep your weight centered over your feet rather than leaning on the handles, which reduces the workout.'),
('Hill sprints', 'cardio', 'none', 'Find a moderate hill and warm up with easy jogging first. Sprint uphill at a hard effort, then walk back down slowly to recover before the next rep. Keep your steps short and land with a slight forward lean into the hill to avoid straining your calves and Achilles.');
